INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (1, "", "えへへっ、ありがとうございます！\nえっと…", 1, 6, 112411, 1060018, "", 10, 11, "");
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES ("", "", "", "", 6, 0, 1060019, "", "", 91, "");
