INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (1, "", "だからもっともっと頑張って\n最高のステージをすることで\nその言葉にお返しが\nできたらなって…", 1, 6, 112411, 1060030, "", 10, 11, "");
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES ("", "", "", "", 6, 0, 1060031, "", "", 91, "");
