INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (1, "", "でも、自分たちで立ち上がって\n再び舞台に立つ姿…\nわたくし、感動いたしました", 1, 7, 105931, 1070041, "", 10, 11, "");
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES ("", "", "", "", 7, 0, 1070042, "", "", 91, "");
